use std::collections::HashMap;
use std::fs;
use std::path::PathBuf;
use std::time::{Duration, SystemTime};
use std::thread;

#[derive(Debug)]
enum FileEvent {
    Created(PathBuf),
    Modified(PathBuf),
    Deleted(PathBuf),
}

fn scan_directory(path: &str) -> Result<HashMap<PathBuf, SystemTime>, String> {
    let mut files = HashMap::new();
    let entries = fs::read_dir(path)
        .map_err(|e| format!("Cannot read directory: {}", e))?;

    for entry in entries {
        let entry = entry.map_err(|e| format!("Error reading entry: {}", e))?;
        let path = entry.path();
        if path.is_file() {
            if let Ok(metadata) = fs::metadata(&path) {
                if let Ok(modified) = metadata.modified() {
                    files.insert(path, modified);
                }
            }
        }
    }
    Ok(files)
}

fn detect_changes(
    old: &HashMap<PathBuf, SystemTime>,
    new: &HashMap<PathBuf, SystemTime>,
) -> Vec<FileEvent> {
    let mut events = Vec::new();

    for (path, new_time) in new {
        match old.get(path) {
            None => events.push(FileEvent::Created(path.clone())),
            Some(old_time) if old_time != new_time => {
                events.push(FileEvent::Modified(path.clone()))
            }
            _ => {}
        }
    }

    for path in old.keys() {
        if !new.contains_key(path) {
            events.push(FileEvent::Deleted(path.clone()));
        }
    }

    events
}

fn main() {
    let watch_path = ".";
    println!("Watching directory: {}", watch_path);

    let mut snapshot = match scan_directory(watch_path) {
        Ok(s) => s,
        Err(e) => {
            eprintln!("Error: {}", e);
            return;
        }
    };
    println!("Initial scan: {} files found", snapshot.len());

    loop {
        thread::sleep(Duration::from_secs(2));

        let new_snapshot = match scan_directory(watch_path) {
            Ok(s) => s,
            Err(e) => {
                eprintln!("Scan error: {}", e);
                continue;
            }
        };

        let events = detect_changes(&snapshot, &new_snapshot);
        if !events.is_empty() {
            for event in &events {
                match event {
                    FileEvent::Created(p) => println!("[CREATED] {:?}", p),
                    FileEvent::Modified(p) => println!("[MODIFIED] {:?}", p),
                    FileEvent::Deleted(p) => println!("[DELETED] {:?}", p),
                }
            }
        }

        snapshot = new_snapshot;
    }
}
